(()=>{"use strict";const r=new WeakMap,t=`\n  <p>${new class{constructor(t){r.set(this,t)}get radius(){return r.get(this)}set radius(t){if(t<=0)throw new Error("invalid radius");r.set(this,t)}draw(){return`drawing a circle with radius of ${r.get(this)}`}}(10).draw()}</p>\n`;document.querySelector(".draw-circle").insertAdjacentHTML("afterbegin",t)})();